const BUILTIN_PATHS = [BUILTIN_DOC, PLATFORM_DOC, ADVANCED_DOC].map(normalizePath);
const BUILTIN_PATH = BUILTIN_PATHS[0]; // default path

// Normalize a learning-path schema v1 document into the internal shape.
// Throws Error(message) with a human-readable reason when invalid.
function normalizePath(doc) {
  if (!doc || typeof doc !== "object") throw new Error("not a JSON object");
  if (doc.schemaVersion !== 1) throw new Error("schemaVersion must be 1");
  const slugRe = /^[a-z0-9][a-z0-9-]*$/;
  if (typeof doc.id !== "string" || !slugRe.test(doc.id)) throw new Error("path.id must be a slug");
  if (!doc.title) throw new Error("path.title required");
  if (!Array.isArray(doc.sections) || !doc.sections.length) throw new Error("path.sections required");
  const seen = new Set();
  const sections = doc.sections.map((s, si) => {
    if (!s.id || !s.title || !Array.isArray(s.units) || !s.units.length)
      throw new Error(`section #${si + 1}: id, title and units are required`);
    return { c: s.title, cs: s.id, tg: s.tagline || "", color: s.color,
      tr: s.units.map((u, ui) => {
        if (!u.id || !u.title || !Array.isArray(u.materials) || !u.materials.length)
          throw new Error(`unit #${ui + 1} in "${s.title}": id, title and materials are required`);
        return { t: u.title, ts: u.id,
          a: u.materials.map((m, mi) => {
            if (!m.id || !m.title || !m.url)
              throw new Error(`material #${mi + 1} in "${u.title}": id, title and url are required`);
            if (seen.has(m.id)) throw new Error(`duplicate material id: "${m.id}"`);
            seen.add(m.id);
            const raw = Array.isArray(m.knowledgePoints) ? m.knowledgePoints : [];
            return { id: m.id, title: m.title, url: m.url,
              contentUrl: m.contentUrl || null, format: m.contentFormat || null,
              summary: m.summary || "", kind: KIND_ACTION[m.kind] ? m.kind : "article",
              diff: DIFF_IN[m.difficulty] || "i",
              pts: raw.map((p, i) => typeof p === "string"
                ? { k: String(i), text: p }
                : { k: p.id || String(i), text: p.text || "" }),
            };
          }) };
      }) };
  });
  return { id: doc.id, title: doc.title, tagline: doc.tagline || "",
    source: doc.source || null, sections };
}

